+        extra: serde_json::Value::Null,
+    }
+}
+
+fn assistant_msg(idx: usize, content: &str, ts: i64, model: &str) -> CanonicalMessage {
+    let mut m = simple_msg(idx, MessageRole::Assistant, content, ts);
+    m.author = Some(model.to_string());
